parameters.jsonBody:
={
  "model": "qwen2.5:3b",
  "stream": false,
  "format": {
    "type": "object",
    "properties": {
      "urgency": { "type": "string", "enum": ["hot", "warm", "cold"] },
      "intent": { "type": "string" },
      "summary": { "type": "string" }
    },
    "required": ["urgency", "intent", "summary"]
  },
  "options": { "temperature": 0 },
  "messages": [
    { "role": "system", "content": "You triage inbound sales leads for a service business. Classify urgency (hot = ready to buy or emergency, warm = interested, cold = just browsing), name the intent in 2-4 words, and write a one-line summary for the sales team." },
    { "role": "user", "content": {{ JSON.stringify($json.body.message || $json.message || "") }} }
  ]
}

parameters.jsCode:
// Ollama returns the schema-constrained JSON as a string in message.content.
const raw = $json.message?.content ?? '{}';
const c = JSON.parse(raw);
const lead = $('Lead Webhook').first().json.body || {};
return [{ json: {
  name: lead.name || 'Unknown',
  urgency: c.urgency,
  intent: c.intent,
  summary: c.summary,
  routed_to: c.urgency === 'hot' ? 'call now' : c.urgency === 'warm' ? 'follow up today' : 'nurture queue'
} }];
